In C++, you can start a new process and connect one file descriptor to its input and output using the `fork()` and `exec()` family of functions. You can also use the `dup2()` function to redirect file descriptors. Here's a basic example:

```cpp
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <iostream>

int main() {
    int pipefd[2];
    if (pipe(pipefd) == -1) {
        std::cerr << "Pipe failed" << std::endl;
        return 1;
    }

    pid_t pid = fork();

    if (pid == -1) {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    }

    if (pid == 0) { // Child process
        close(pipefd[1]); // Close write end in child
        dup2(pipefd[0], STDIN_FILENO); // Redirect stdin to read end of pipe
        close(pipefd[0]); // Close read end in child

        close(STDOUT_FILENO); // Close stdout in child
        dup2(pipefd[1], STDOUT_FILENO); // Redirect stdout to write end of pipe
        close(pipefd[1]); // Close write end in child

        execlp("ls", "ls", "-l", NULL); // Execute a command
        std::cerr << "Execute failed" << std::endl;
        return 1;
    } else { // Parent process
        close(pipefd[0]); // Close read end in parent
        close(pipefd[1]); // Close write end in parent

        std::string output;
        char buffer[512];
        int bytes_read;

        while ((bytes_read = read(pipefd[0], buffer, sizeof(buffer))) > 0) {
            output.append(buffer, bytes_read);
        }

        std::cout << "Output from child process: " << output << std::endl;

        wait(NULL); // Wait for the child process to finish
    }

    return 0;
}
```

